using Microsoft.AspNetCore.Authorization;using Microsoft.AspNetCore.Mvc;using Microsoft.EntityFrameworkCore;using verii_metivon_api.Core.Auth;using verii_metivon_api.Core.Persistence;using verii_metivon_api.Modules.Receiving.Application.Services;namespace verii_metivon_api.Modules.Receiving.Api;[ApiController,Authorize,Route("api/goods-receipts")]public sealed class GoodsReceiptsController(IGoodsReceiptService s,MetivonDbContext db):ControllerBase{[HttpGet]public async Task<IActionResult>List([FromQuery]GoodsReceiptQuery q,CancellationToken ct){var r=await s.GetPagedAsync(q,ct);return StatusCode(r.StatusCode,r);}[HttpPost]public async Task<IActionResult>Create(CreateGoodsReceiptRequest x,CancellationToken ct){var r=await s.CreateAsync(x,ct);return StatusCode(r.StatusCode,r);}[HttpPost("{id:long}/post")]public async Task<IActionResult>Post(long id,CancellationToken ct){var r=await s.PostAsync(id,ct);return StatusCode(r.StatusCode,r);}[HttpGet("{id:long}/labels")]public async Task<IActionResult>Labels(long id,CancellationToken ct){var receipt=await db.GoodsReceipts.AsNoTracking().Where(x=>x.Id==id).Select(x=>new{x.Id,x.ReceiptNumber,x.ReceiptDate,Warehouse=x.Warehouse.Code}).FirstOrDefaultAsync(ct);if(receipt is null)return NotFound(ApiResponse<object>.Error("Goods receipt not found.",404));var lines=await db.GoodsReceiptLines.AsNoTracking().Where(x=>x.GoodsReceiptId==id).Include(x=>x.Serials).Select(x=>new{x.Id,x.LineNumber,x.ProductId,ProductCode=x.Product.Code,ProductName=x.Product.Name,TrackingType=x.Product.TrackingType.ToString(),Barcode=x.Product.Barcodes.Where(b=>b.IsActive).OrderByDescending(b=>b.IsPrimary).Select(b=>b.Barcode).FirstOrDefault(),x.LotNumber,x.ManufactureDate,x.ExpiryDate,x.AcceptedQuantity,SerialNumbers=x.Serials.Select(s=>s.SerialNumber).ToList()}).ToListAsync(ct);var labels=lines.SelectMany(x=>x.SerialNumbers.Count>0?x.SerialNumbers.Select(serial=>new{x.ProductCode,x.ProductName,x.Barcode,x.LotNumber,SerialNumber=(string?)serial,x.ManufactureDate,x.ExpiryDate,Quantity=1m,receipt.ReceiptNumber,receipt.ReceiptDate,receipt.Warehouse}):new[]{new{x.ProductCode,x.ProductName,x.Barcode,x.LotNumber,SerialNumber=(string?)null,x.ManufactureDate,x.ExpiryDate,Quantity=x.AcceptedQuantity,receipt.ReceiptNumber,receipt.ReceiptDate,receipt.Warehouse}}).ToList();return Ok(ApiResponse<object>.Ok(new{receipt,labels}));}}
